import React, { Component } from "react";
import Ridewatch from "./Ridewatch";

const tryRequire = (path) => {
  try {
    return require(`${path}`);
  } catch (err) {
    return null;
  }
};

function soundex(name) {
  let s = [];
  let si = 1;
  let c;

  //              ABCDEFGHIJKLMNOPQRSTUVWXYZ
  let mappings = "01230120022455012623010202";

  s[0] = name[0].toUpperCase();

  for (let i = 1, l = name.length; i < l; i++) {
    c = name[i].toUpperCase().charCodeAt(0) - 65;

    if (c >= 0 && c <= 25) {
      if (mappings[c] !== "0") {
        if (mappings[c] !== s[si - 1]) {
          s[si] = mappings[c];
          si++;
        }

        if (si > 3) {
          break;
        }
      }
    }
  }

  if (si <= 3) {
    while (si <= 3) {
      s[si] = "0";
      si++;
    }
  }

  return s.join("");
}

// RidewatchList renders a single series section on the Checklist page.
// It shows a clickable header image and a list of Ridewatch buttons for that series.
// If the series is in invisibleHeaders, the section is hidden (renders an empty div).
export class RidewatchList extends Component {
  constructor(props) {
    super(props);
    this.state = {
      imgsrc: this.props.imgsrc,
      allChecked: false,
      Collapsed: false,
      Checked: "false",
      invisibleHeaders: this.props.invisibleHeaders,
    };
    this.checkAll = this.checkAll.bind(this);
  }

  // Builds the URL for the series header image (e.g. header-zio.png).
  headerUrlGet() {
    var headerUrl =
      process.env.PUBLIC_URL +
      "/images/icons/" +
      "header-" +
      this.props.series +
      ".png";
    return headerUrl;
  }

  // Maps the watches for this series into individual Ridewatch components.
  ridewatchMaker() {
    let ridewatches = this.props.watches.map((watch) => {
      if (watch.series === this.props.series) {
        return (
          <li>
            <Ridewatch
              //imgsrc={this.localImageUrl(watch)}
              imgsrc={
                process.env.PUBLIC_URL + "/images/watches/" + watch.id + ".png"
              }
              alt={watch.name}
              soundex={soundex(watch.name)}
              identity={this.props.katakana ? watch.katakana : watch.name}
              year={watch.year}
              id={watch.id}
              key={watch.id}
              series={watch.series}
              checked={this.state.Checked}
              totalOwnedUpdate={this.props.totalOwnedUpdate}
              allChecked={this.state.allChecked}
            />
          </li>
        );
      }
    });
    return ridewatches;
  }

  // Toggles all watches in this series between owned and not owned.
  // Updates localStorage for each watch and refreshes the owned counter.
  checkAll() {
    const watches = this.props.watches;
    if (this.state.allChecked === false) {
      watches.forEach(watch => localStorage.setItem(watch.id, watch.id));
      this.setState({ allChecked: true });
    } else {
      watches.forEach(watch => localStorage.removeItem(watch.id));
      this.setState({ allChecked: false });
    }
    this.props.totalOwnedUpdate();
  }

  // If this series is in invisibleHeaders, renders an empty div (hidden).
  // Otherwise renders the series header image and the full list of watch buttons.
  // Clicking the header image calls headerToggle to hide this series.
  render() {
    if (this.props.invisibleHeaders.includes(this.props.series)) {
      return <div className={this.props.series + "-div"}></div>;
    } else {
      return (
        <div className={this.props.series + "-background"}>
          <div className={this.props.series + "-div"}>
            <h1
              id={this.props.series + "-header"}
              className={this.props.series + "-open"}
            >
              <i id={this.props.series + "-header"} />
              <div>
                <img
                  className={"listHeaderImage"}
                  src={this.headerUrlGet()}
                  onClick={() => this.props.headerToggle(this.props.series)}
                ></img>
                <button
                  className={"checkAllButton"}
                  onClick={() => this.checkAll()}
                >
                  {this.state.allChecked ? "Uncheck All" : "Check All"}
                </button>
              </div>
            </h1>
            <ul className={this.props.series}>{this.ridewatchMaker()}</ul>
          </div>
        </div>
      );
    }
  }
}

export default RidewatchList;
